final:
module top_module (
    input [3:0] r,
    output reg obf_b
);

    always @(*) begin
        case (r)
            4'b0000: obf_b = 1;
            4'b0001: obf_b = 0;
            4'b0010: obf_b = 1;
            4'b0011: obf_b = 0;
            4'b0100: obf_b = 1;
            4'b0101: obf_b = 0;
            4'b0110: obf_b = 1;
            4'b0111: obf_b = 0;
            4'b1000: obf_b = 1;
            4'b1001: obf_b = 0;
            4'b1010: obf_b = 1;
            4'b1011: obf_b = 0;
            4'b1100: obf_b = 1;
            4'b1101: obf_b = 0;
            4'b1110: obf_b = 1;
            4'b1111: obf_b = 0;
            default: obf_b = 0; // Default case
        endcase
    end
endmodule
